Here is a readable reconstruction of the real logic:

```js
const TAU = 6.283;
const PHI = 1.618;
const INV_SQRT2 = 0.707;

const config = {
  attraction: 4000,
  frictionCoeff: 0.004,
  amplification: 0.92,
  dispersal: 0.0003,
  streamMax: 40,
  streamDecay: 0.04,
  theta: 0.06
};

const nodes = [
  { id: 'hub', label: 'Hub', r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: 'alpha', label: 'Alpha', r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: 'beta', label: 'Beta', r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: 'gamma', label: 'Gamma', r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: 'delta', label: 'Delta', r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

const links = [
  { a: 'hub', b: 'alpha', rest: 160, k: 0.006 },
  { a: 'hub', b: 'beta', rest: 160, k: 0.005 },
  { a: 'hub', b: 'gamma', rest: 170, k: 0.004 },
  { a: 'hub', b: 'delta', rest: 170, k: 0.004 },
  { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta', rest: 200, k: 0.002 },
  { a: 'gamma', b: 'delta', rest: 220, k: 0.002 },
  { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

const camera = { x: 400, y: 300, zoom: 1 };
const targetCamera = { x: 400, y: 300, zoom: 1 };

const streamParticles = [];
let tick = 0;

function getNodeById(id) {
  for (const node of nodes) {
    if (node.id === id) return node;
  }
  return null;
}

function updateNodePhysics() {
  for (let i = 0; i < nodes.length; i++) {
    for (let j = i + 1; j < nodes.length; j++) {
      const dx = nodes[i].x - nodes[j].x;
      const dy = nodes[i].y - nodes[j].y;
      const dist = Math.sqrt(dx * dx + dy * dy) || 1;
      const force = config.attraction / (dist * dist);
      const fx = dx / dist * force;
      const fy = dy / dist * force;

      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  for (const link of links) {
    const a = getNodeById(link.a);
    const b = getNodeById(link.b);
    if (!a || !b) continue;

    const dx = b.x - a.x;
    const dy = b.y - a.y;
    const dist = Math.sqrt(dx * dx + dy * dy) || 1;
    const stretch = dist - link.rest;
    const force = (link.k || config.amplification) * stretch;

    a.vx += dx / dist * force;
    a.vy += dy / dist * force;
    b.vx -= dx / dist * force;
    b.vy -= dy / dist * force;
  }

  for (const node of nodes) {
    node.vx += (400 - node.x) * config.dispersal;
    node.vy += (300 - node.y) * config.dispersal;

    node.vx *= config.amplification;
    node.vy *= config.amplification;

    node.x += node.vx;
    node.y += node.vy;
  }
}

function emitParticle() {
  if (streamParticles.length >= config.streamMax) return;

  const node = nodes[Math.floor(Math.random() * nodes.length)];
  const angle = Math.random() * TAU;
  const speed = 0.3 + Math.random() * INV_SQRT2;

  streamParticles.push({
    x: node.x,
    y: node.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + (Math.random() * PHI + INV_SQRT2)
  });
}

function updateParticles() {
  for (let i = streamParticles.length - 1; i >= 0; i--) {
    const p = streamParticles[i];

    p.vx *= (1 - config.streamDecay * 0.125);
    p.vy *= (1 - config.streamDecay * 0.125);

    p.x += p.vx;
    p.y += p.vy;
    p.age++;

    if (p.age > p.maxAge) {
      streamParticles.splice(i, 1);
    }
  }
}

function updateCamera() {
  camera.x += (targetCamera.x - camera.x) * config.theta;
  camera.y += (targetCamera.y - camera.y) * config.theta;
  camera.zoom += (targetCamera.zoom - camera.zoom) * config.theta;
}

function step() {
  updateNodePhysics();
  updateParticles();
  updateCamera();

  if (tick % 3 === 0) {
    emitParticle();
  }

  tick++;
}

setInterval(step, 16);
